INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$HTTP and HTTPS mocking$q$, $q$Define expectations that return specific responses for matching requests, simulating any REST or web API dependency.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Multi-protocol support$q$, $q$Mocks and proxies HTTP/1.1, HTTP/2, HTTP/3, gRPC, WebSockets and raw TCP traffic on a single port.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Record and replay$q$, $q$Captures real traffic to a target system and replays it later to reproduce production behavior in tests.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Request verification$q$, $q$Asserts that expected requests were or were not made, letting MockServer double as a test verification tool.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Fault and chaos injection$q$, $q$Introduces latency, errors, dropped connections and malformed responses to test resilience under failure.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Dynamic response templating$q$, $q$Generates responses that react to the incoming request using Velocity, Mustache or JavaScript templates.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Breakpoints$q$, $q$Pauses live traffic to inspect or modify a request or response before it continues, useful for debugging integrations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Broad client and deployment support$q$, $q$Ships client libraries for Java, JavaScript, Python, Ruby, Go, .NET, Rust and PHP, plus Docker, CLI and JVM embedding options.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Completely free and open source with no usage limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Very broad protocol coverage including gRPC, WebSockets, TCP and HTTP/3$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Embeds directly into JVM test suites for fast, isolated integration testing$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Supports advanced service virtualization features like recording, replay and chaos injection$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Active GitHub project with clients across many languages$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$No managed hosted offering, so teams must run and maintain their own instance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Steeper learning curve than lightweight mocking tools for non-JVM teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$No official commercial support or SLA$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Documentation can be dense for newcomers unfamiliar with expectation matching syntax$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Less polished UI compared to some commercial API mocking platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Is MockServer free to use?$q$, $q$Yes. MockServer is fully open source under the Apache 2.0 license and free to self-host, with no paid tiers or usage caps.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$What is MockServer used for?$q$, $q$It is used to mock and proxy HTTP, gRPC, WebSocket and TCP dependencies during integration testing, letting teams simulate third-party APIs or unstable services in a controlled way.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Is MockServer the same as Mockoon?$q$, $q$No. MockServer and Mockoon are separate, unrelated projects despite the similar naming. MockServer is a Java-based server and proxy, while Mockoon is a desktop-first mock API tool.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Can MockServer mock gRPC and WebSocket traffic?$q$, $q$Yes. In addition to standard HTTP and HTTPS, MockServer supports gRPC, WebSockets, TCP and, in newer versions, HTTP/3 and message brokers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Does MockServer support Docker?$q$, $q$Yes. MockServer publishes official Docker images, making it easy to run in CI pipelines or local development environments.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Who created MockServer?$q$, $q$MockServer was created by developer James D. Bloom and has been maintained as an open-source project since around 2013.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Integration test isolation$q$, $q$QA and backend engineers mock third-party APIs and internal microservices so integration tests run reliably without depending on live systems.$q$, $q$Backend and QA engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Resilience and chaos testing$q$, $q$Teams inject latency, errors and dropped connections to verify how an application behaves when dependencies fail.$q$, $q$SRE and platform teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Contract and CI testing$q$, $q$Engineering teams embed MockServer inside CI pipelines to verify request/response contracts between services before deployment.$q$, $q$DevOps and CI/CD engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full HTTP, HTTPS, gRPC, WebSocket and TCP mocking","Record and replay","Fault and chaos injection","Client libraries for major languages","Docker and JVM embedding support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MockServer is a self-hosted, open-source framework for mocking and proxying the HTTP, HTTPS, gRPC, WebSocket and TCP services an application depends on. Rather than testing against real third-party APIs or unstable internal microservices, teams point their application at MockServer, which returns configured or templated responses on demand.$q$, $q$Created by developer James D. Bloom and written in Java on top of Netty, MockServer can run embedded inside a test process, as a standalone JVM server, or as a Docker container. It ships client libraries for many languages and a plain REST API, so it fits into almost any test stack regardless of the application's own language.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$MockServer goes beyond static stubbing. It supports request verification as test assertions, recording and replaying real traffic to reproduce production scenarios, and breakpoints that let engineers pause and modify requests or responses mid-flight for debugging.$q$, $q$It also supports fault and chaos injection (latency, dropped connections, malformed responses) for resilience testing, dynamic response templating with Velocity, Mustache or JavaScript, and declarative load scenarios for basic performance testing. Recent versions add a built-in Model Context Protocol server so AI coding assistants can create and inspect expectations directly.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$MockServer is completely free and open source under the Apache 2.0 license, with no paid tier, usage limits, or SaaS account requirement. Teams self-host it via a JAR, embedded dependency, or Docker image, so the only real cost is the infrastructure used to run it.$q$, $q$Because there is no commercial vendor, there is no official support SLA; support comes from community channels, documentation, and the GitHub repository rather than a paid contract.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3b64d2ca-a1dc-4aae-a2ec-4b86bf0052dc', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Serverless GPU compute$q$, $q$Run AI training, fine-tuning and inference jobs on A10G, A100 and H100 GPUs with per-second billing and automatic scaling.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Python-native SDK$q$, $q$Deploy functions to the cloud using ordinary Python decorators instead of Dockerfiles or Kubernetes manifests.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Fast cold starts and autoscaling$q$, $q$Containers start in seconds and automatically scale to zero when idle, minimizing wasted spend.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Web endpoint deployment$q$, $q$Turn Python functions into HTTP endpoints for serving models and APIs with minimal configuration.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Persistent storage volumes$q$, $q$Attach durable storage volumes to functions for datasets, checkpoints, and model weights across runs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Scheduled and event-driven jobs$q$, $q$Trigger functions on a cron schedule or in response to events for batch processing and pipelines.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Sandboxed code execution$q$, $q$Run untrusted or dynamically generated code in isolated, secure containers, useful for AI agent workloads.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Per-second usage billing$q$, $q$Pay only for the exact compute time consumed, billed at second-level granularity across CPU and GPU resources.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Python-native developer experience removes the need for Docker and Kubernetes expertise$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Fine-grained per-second billing keeps costs closely tied to actual usage$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Fast cold starts make serverless GPU workloads practical for interactive use cases$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Free tier with monthly credits lowers the barrier for individual developers and small teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Backed by well-known investors and a founding team with strong open-source and infrastructure credibility$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$GPU costs can still add up quickly for sustained, high-volume training workloads$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Primarily oriented toward Python; less native support for other languages$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Team and Enterprise plans add a base subscription fee on top of usage costs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Newer platform compared to established cloud providers, with a smaller enterprise track record$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Advanced networking and compliance features may lag larger hyperscalers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$What is Modal used for?$q$, $q$Modal is used to run AI, machine learning and data workloads, including GPU-accelerated training, fine-tuning, batch inference and data pipelines, without managing servers or Kubernetes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$How does Modal pricing work?$q$, $q$Modal bills by the second for CPU, GPU and memory usage. It offers a free Starter tier with monthly compute credits, a $250 per month Team plan plus usage, and custom Enterprise pricing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Does Modal support GPUs?$q$, $q$Yes. Modal offers serverless access to GPUs including A10G, A100 and H100, billed per second based on actual usage.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Who founded Modal?$q$, $q$Modal was founded in 2021 by Erik Bernhardsson, former engineering leader at Spotify, and co-founder and CTO Akshat Bubna.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Is Modal free to try?$q$, $q$Yes. Modal's Starter plan is free and includes $30 per month in compute credits along with limited workspace seats and concurrency.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$How much funding has Modal raised?$q$, $q$Modal raised an $87 million Series B in September 2025 led by Lux Capital, reaching a valuation of about $1.1 billion.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$AI model training and fine-tuning$q$, $q$ML teams run GPU-intensive training and fine-tuning jobs on demand without provisioning or managing dedicated GPU clusters.$q$, $q$ML engineers and data scientists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Serving inference APIs$q$, $q$Developers deploy trained models as scalable web endpoints that automatically scale with request volume.$q$, $q$AI application developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Batch data processing$q$, $q$Data teams schedule and run large-scale batch jobs and pipelines using serverless Python functions.$q$, $q$Data engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Starter$q$, $q$Free$q$, $q$Monthly$q$, NULL, $q$["$30/month in compute credits","3 workspace seats","100 container concurrency","10 GPU concurrency"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Team$q$, $q$$250/month + compute usage$q$, $q$Monthly$q$, NULL, $q$["$100/month in credits","Unlimited seats","1,000 container concurrency","50 GPU concurrency"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Custom limits and concurrency","Dedicated support","Advanced security and compliance options"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Modal is a serverless cloud platform purpose-built for AI, machine learning, and data workloads. Instead of provisioning servers or managing Kubernetes, developers write plain Python functions and decorate them to run in the cloud, with Modal handling containerization, scaling, and GPU allocation automatically.$q$, $q$Founded in 2021 by Erik Bernhardsson and Akshat Bubna, Modal reached unicorn status after an $87 million Series B in September 2025 led by Lux Capital. The company is headquartered in New York with additional offices in San Francisco and Stockholm.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Modal's headline feature is serverless GPU compute with per-second billing, supporting GPUs like A10G, A100 and H100 alongside standard CPU functions. Containers spin up quickly and scale to zero automatically when not in use, so teams only pay for active compute time.$q$, $q$Beyond raw compute, Modal supports scheduled and event-triggered jobs, persistent storage volumes for datasets and model weights, one-line web endpoint deployment for serving models as APIs, and sandboxed execution environments, all driven from a Python-native SDK rather than YAML or Dockerfiles.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c5f50ff9-292d-461f-9877-3ee54d35032f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Modal uses usage-based, per-second billing for CPU, GPU and memory consumption. A free Starter tier provides $30 per month in compute credits along with a handful of workspace seats and modest concurrency limits, making it accessible for individual developers and small projects.$q$, $q$The Team plan costs $250 per month plus metered compute usage, and includes $100 in monthly credits, unlimited seats, and significantly higher container and GPU concurrency. Enterprise plans are custom-priced and add features like dedicated support and higher limits for larger organizations.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Web-based admin panel$q$, $q$Centralized panel for managing domains, mailboxes, aliases, and permissions without touching Postfix or Dovecot configuration files directly.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Integrated webmail$q$, $q$Full-featured webmail client with calendar and address book built into the platform.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Multi-domain, unlimited mailbox support$q$, $q$Hosts unlimited domains, mailboxes, and aliases from a single Modoboa installation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Sieve filters and auto-responders$q$, $q$Lets users and admins configure mail filtering rules and automatic reply messages.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Email authentication and reputation tools$q$, $q$Built-in support for SPF, DKIM, DMARC, and DNSBL checks to protect deliverability.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Automatic TLS via Let's Encrypt$q$, $q$Provisions and renews TLS certificates automatically to secure mail traffic.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Modular extension architecture$q$, $q$All features are implemented as extensions, letting administrators customize which capabilities are enabled.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Monitoring and statistics$q$, $q$Provides real-time statistics and monitoring dashboards for mail traffic and server health.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Completely free and open source with no licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Modern Django and Vue-based admin interface, unusual for a self-hosted mail project$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Built on proven, widely-used components (Postfix, Dovecot)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Strong built-in security and reputation tooling (SPF, DKIM, DMARC)$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Active open-source community with hundreds of thousands of mailboxes deployed$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Requires self-hosting and server administration knowledge to deploy and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$No official managed cloud version directly from the core project$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Commercial Pro features and professional support pricing are not fully transparent$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Smaller ecosystem and plugin marketplace compared to commercial email platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Documentation is comprehensive but assumes familiarity with Linux mail server concepts$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Is Modoboa free?$q$, $q$Yes, the core Modoboa platform is free and open source under the ISC license. A paid Modoboa Pro extension suite and professional services are also available for organizations that want additional support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$What technology is Modoboa built on?$q$, $q$Modoboa is written in Python 3 using the Django framework for the backend and Vue.js for the frontend, and it manages Postfix and Dovecot as the underlying mail server components.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Who created Modoboa?$q$, $q$Modoboa was created by French developer Antoine Nguyen, originally under the project name MailNG before it was renamed.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Do I need server administration skills to use Modoboa?$q$, $q$Yes. Modoboa is self-hosted software, so you need a Linux server and basic sysadmin knowledge to install and maintain it, though the web panel simplifies day-to-day administration.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Does Modoboa include webmail?$q$, $q$Yes, Modoboa ships with an integrated webmail client that includes calendar and address book functionality.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$How does Modoboa compare to Mailcow or iRedMail?$q$, $q$Modoboa, Mailcow, and iRedMail are all open-source self-hosted mail platforms built around Postfix and Dovecot; they differ mainly in admin UI design, extension architecture, and deployment method (Modoboa favors a Django/Vue app, Mailcow favors Docker containers).$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Self-hosted email for small businesses$q$, $q$Small businesses run their own domain email infrastructure instead of paying for Google Workspace or Microsoft 365 seats.$q$, $q$Small business IT admins$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Hosting provider mail platform$q$, $q$Web hosts and MSPs use Modoboa to offer multi-tenant email hosting to their own customers.$q$, $q$Hosting providers and MSPs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Privacy-focused personal email hosting$q$, $q$Privacy-conscious individuals and developers self-host their own mail server to control their data.$q$, $q$Developers and privacy-focused users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Community (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited domains and mailboxes","Webmail, calendar, address book","Admin panel and monitoring","SPF, DKIM, DMARC support","ISC-licensed open source"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$Modoboa Pro / Professional Services$q$, $q$From approximately EUR 150 for setup assistance$q$, $q$One-time or custom$q$, NULL, $q$["Installation and upgrade assistance","Issue troubleshooting support","Annual server maintenance options","Commercial extension suite"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Modoboa is a free, open-source platform for hosting and administering email. It wraps proven mail server components, Postfix for sending mail and Dovecot for retrieving it, in a modern, easy-to-use web administration panel and webmail client.$q$, $q$Created by French developer Antoine Nguyen and originally released under the name MailNG, Modoboa is written in Python using Django and Vue.js, and stores its configuration in a SQL database such as MySQL, MariaDB, PostgreSQL, or SQLite. The community reports the platform now powers hundreds of thousands of mailboxes worldwide.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Modoboa provides multi-domain and multi-mailbox management, an integrated webmail client with calendar and address book, and Sieve-based filtering and auto-responders. Administrators get real-time statistics, monitoring, and permission management from a single panel.$q$, $q$On the security side, Modoboa supports SPF, DKIM, DMARC, and DNSBL checks alongside automatic TLS via Let's Encrypt, helping protect domain reputation and deliverability. Because all functionality is built as modular extensions, administrators can enable only the features they need.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Modoboa platform is entirely free and open source under the ISC license, with no cost to download, self-host, or use at any scale. Users are responsible for their own server infrastructure.$q$, $q$For organizations that want commercial support, the team also offers Modoboa Pro, a paid extension suite, along with professional services such as installation, upgrades, and issue troubleshooting, priced individually starting from roughly 150 euros for setup assistance.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba61acd7-9961-41fb-a375-101e19f2f40e', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Markup-agnostic templating$q$, $q$Chunks, Snippets, Templates, and Template Variables give developers full control over HTML output with no forced theme structure.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Resource-based content model$q$, $q$Flexible content architecture that supports simple pages as well as complex, custom content structures beyond a typical post/page model.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Manager admin interface$q$, $q$A back-end panel for editing content, managing resources, and configuring site settings.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Granular permissions$q$, $q$Role- and user-based access control for managing who can edit or publish specific content.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$SEO-friendly URLs$q$, $q$Clean, customizable URL structures supported out of the box without requiring additional plugins.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Extras and plugin ecosystem$q$, $q$Community-built extras extend MODX with additional functionality while keeping the core lightweight.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Multi-language support$q$, $q$Built-in tools for managing multi-language and localized content within a single install.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$MODX Cloud managed hosting$q$, $q$Optional managed hosting platform purpose-built for MODX sites, including staging, CDN/WAF, and failover add-ons.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Complete control over HTML markup with no imposed theme structure$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Free, open-source core with a long, stable operating history since 2004$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Flexible resource-based content model suited to custom site architectures$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Strong SEO-friendly URL handling and clean output by default$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Optional managed MODX Cloud hosting purpose-built for the platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Steeper learning curve than theme-driven CMS platforms like WordPress$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Smaller plugin and extras ecosystem compared to WordPress$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Requires more developer involvement to build a site from scratch$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Smaller community and slower feature cadence than larger CMS projects$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$MODX Cloud pricing is higher than many generic shared hosting options$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Is MODX free?$q$, $q$Yes, the core MODX CMS is free and open source and can be self-hosted on any PHP-compatible server. Paid options include community-built premium add-ons and MODX Cloud managed hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Who created MODX?$q$, $q$MODX was created in 2004 by Raymond Irving and Ryan Thrash, with Jason Coward joining the project leadership in 2005. MODX LLC was formally founded in Dallas, Texas in 2010.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$What is the difference between MODX Evolution and MODX Revolution?$q$, $q$MODX Evolution was the original CMS released around 2005; MODX Revolution, released in 2010, was a complete architectural rewrite and is the actively developed version today.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$How much does MODX Cloud cost?$q$, $q$MODX Cloud managed hosting starts around $39 per month for a Base plan, with Pro around $99 per month and Business around $349 per month; custom Enterprise pricing starts around $4,000 per month.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Is MODX good for beginners?$q$, $q$MODX is more developer-oriented than beginner-friendly CMS platforms like WordPress, since it requires building templates and markup from scratch rather than using pre-built themes.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$How does MODX compare to WordPress?$q$, $q$MODX gives developers full control over HTML markup with no default theme system, while WordPress relies on themes and a much larger plugin ecosystem; MODX is generally favored for fully custom-designed sites.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Custom-designed agency websites$q$, $q$Web agencies use MODX to build fully custom-branded client sites without fighting a theme system.$q$, $q$Web development agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Semantic, SEO-focused marketing sites$q$, $q$Businesses use MODX for clean, hand-crafted HTML output that supports strong on-page SEO.$q$, $q$Marketing teams and SEO-focused businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Managed hosting for mission-critical sites$q$, $q$Organizations use MODX Cloud's Pro Sites plans for high-availability hosting with CDN/WAF and failover protection.$q$, $q$Enterprises and can't-fail marketing sites$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full MODX Revolution CMS","Self-hosted on any PHP server","Community extras and plugins","Full markup control"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$MODX Cloud Base$q$, $q$From $39/month$q$, $q$Monthly$q$, NULL, $q$["Managed MODX Cloud hosting","Backstage staging (add-on)","Cloud Edge CDN/WAF (add-on)"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$MODX Cloud Pro$q$, $q$From $99/month$q$, $q$Monthly$q$, NULL, $q$["Higher resource limits","Proactive monitoring","Faster support response"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$MODX Cloud Business$q$, $q$From $349/month$q$, $q$Monthly$q$, NULL, $q$["Higher performance tier","Failover protection option","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$Enterprise$q$, $q$From approximately $4,000/month (3-year commitment)$q$, $q$Annual/Custom$q$, NULL, $q$["Dedicated infrastructure","Custom SLAs","Private server options"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MODX is an open-source content management system built in PHP that gives developers complete control over a site's HTML output rather than forcing a fixed theme structure. It was created in 2004 by Raymond Irving and Ryan Thrash, who wanted a CMS that could produce fully semantic, CSS-styled markup, and the project has been maintained continuously since.$q$, $q$MODX LLC was formally founded in Dallas, Texas in May 2010, the same year the team released MODX Revolution, a full rewrite that replaced the original MODX Evolution codebase and remains the current actively developed version.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$MODX uses a tag-based templating system built from Chunks, Snippets, Templates, and Template Variables, giving developers precise, markup-agnostic control over front-end output instead of relying on pre-built themes. Its resource-based content model supports both simple brochure sites and more complex, custom content structures.$q$, $q$The platform includes a manager back end for editing content, a permissions and user-role system, multi-language support, SEO-friendly URLs by default, and an ecosystem of community-built extras and plugins for adding functionality without touching core code.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core MODX software is free and open source, and can be downloaded and self-hosted on any PHP-compatible server at no cost. Premium add-ons built by community developers have been available since 2013 for teams that want extra functionality.$q$, $q$For teams that prefer managed hosting, MODX Cloud offers tiered plans starting around $39 per month for a Base plan, scaling to $99 per month for Pro and $349 per month for Business, with custom Enterprise pricing starting around $4,000 per month on longer commitments. Add-ons like staging environments, CDN/WAF protection, and failover are priced separately.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba2afed9-4dd0-452e-8365-2334d0c54742', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Cross-channel campaign orchestration$q$, $q$Runs coordinated campaigns across email, SMS, push, in-app, WhatsApp, and web push from a single platform.$q$, 0);
