INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Behavioral and demographic segmentation$q$, $q$Builds live audience segments from real-time behavioral, demographic, and transactional data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Drag-and-drop journey builder$q$, $q$No-code visual builder for creating complex, multi-step, multi-channel customer journeys.$q$, 3);
