INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Real-time transactional alerts$q$, $q$Triggers timely, event-driven messages such as order confirmations or fraud alerts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$A/B and multivariate testing$q$, $q$Tests campaign variants to optimize messaging, timing, and channel selection.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Enterprise governance and security$q$, $q$Role-based access, audit logs, firewall protection, and PII encryption for large, regulated organizations.$q$, 7);
