INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Unified platform covering nearly every major engagement channel including WhatsApp$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Powerful behavioral segmentation and journey orchestration tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Well suited to high-volume, mobile-first consumer apps and e-commerce brands$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Enterprise-grade governance, security, and compliance controls available$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Custom, quote-based pricing makes upfront cost comparison difficult$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Minimum one-year contract commitments reduce flexibility for smaller teams$q$, 1);
