INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Steeper onboarding and setup complexity compared to simpler email marketing tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$What is MoEngage used for?$q$, $q$MoEngage is used to run personalized, cross-channel marketing campaigns across email, push, SMS, WhatsApp, in-app, and web push, powered by AI-driven segmentation and send-time optimization.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$How much does MoEngage cost?$q$, $q$MoEngage uses custom, quote-based pricing tied to Monthly Tracked Users. Reports indicate the Growth plan starts around $4,999 to $5,999 per month and Enterprise starts around $19,999 or more per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Who founded MoEngage?$q$, $q$MoEngage was founded in 2014 in Bengaluru, India by Raviteja Dodda and Yashwanth Kumar.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Does MoEngage support WhatsApp marketing?$q$, $q$Yes, MoEngage supports WhatsApp Business API messaging as one of its core engagement channels alongside email, SMS, push, and in-app messaging.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$What is Sherpa AI in MoEngage?$q$, $q$Sherpa AI is MoEngage's built-in AI engine that powers send-time optimization, churn prediction, and real-time content and channel personalization.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$How does MoEngage compare to Braze or Clevertap?$q$, $q$MoEngage, Braze, and Clevertap are all cross-channel customer engagement platforms; MoEngage is often noted for competitive pricing and strong traction in mobile-first markets like India and Southeast Asia alongside its US presence.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Mobile app lifecycle marketing$q$, $q$Consumer app companies use MoEngage to send personalized push, in-app, and email messages based on user behavior.$q$, $q$Mobile app growth and marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$E-commerce personalization campaigns$q$, $q$Online retailers use MoEngage to trigger cart abandonment, promotional, and loyalty campaigns across channels.$q$, $q$E-commerce marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Churn prevention and retention$q$, $q$Product and growth teams use MoEngage's AI churn prediction to proactively re-engage at-risk users.$q$, $q$Product growth and retention teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Growth$q$, $q$From approximately $4,999-$5,999/month (varies by MAU)$q$, $q$Annual (minimum 1-year commitment)$q$, NULL, $q$["Unlimited email, SMS, push, in-app, WhatsApp and web push","Unlimited segments","Predictive AI and real-time personalization"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$Enterprise$q$, $q$From approximately $19,999+/month$q$, $q$Annual (minimum 1-year commitment)$q$, NULL, $q$["Full AI orchestration","Dedicated SLAs","Enterprise security and compliance controls","Advanced governance (RBAC, audit logs, PII encryption)"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MoEngage is a customer engagement platform that helps marketing and growth teams run personalized campaigns across email, push notifications, SMS, WhatsApp, in-app messages, and web push from a single system. It combines customer data unification, audience segmentation, and cross-channel orchestration in one platform.$q$, $q$Founded in 2014 in Bengaluru by Raviteja Dodda and Yashwanth Kumar, MoEngage has grown into a dual-headquartered company with hubs in San Francisco and Bengaluru, backed by roughly $458 million in total funding from investors including A91 Partners and ChrysCapital.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$MoEngage's AI layer, branded Sherpa AI, powers send-time optimization, churn prediction, and real-time personalization decisions across channels. Its segmentation engine builds live audiences from behavioral and demographic data, and its drag-and-drop journey builder supports complex multi-step campaigns without coding.$q$, $q$The platform also offers customer journey analytics, A/B testing, real-time transactional alerts, and enterprise governance features such as role-based access controls, audit logs, and PII encryption for regulated industries like fintech and healthcare adjacent brands.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e8e2b2b1-e626-4b69-b056-d2cfa9a442ef', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$MoEngage prices custom contracts based primarily on Monthly Tracked Users (MTU) rather than a flat platform fee. Its two published tiers are Growth and Enterprise, both requiring a quote and typically a minimum one-year commitment.$q$, $q$The Growth plan is reported to start around $4,999 to $5,999 per month depending on monthly active user volume and includes unlimited messaging across supported channels. The Enterprise plan is reported to start around $19,999 or more per month and adds full AI orchestration, dedicated SLAs, and advanced compliance and security controls.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Unified payments API$q$, $q$Single integration to accept dozens of European and international payment methods without separate setups per method.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Local European payment methods$q$, $q$Native support for high-conversion local methods like iDEAL, Wero, SEPA Direct Debit, and Bancontact.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$In-person payments$q$, $q$Point-of-sale card readers and terminals that integrate with the same Mollie dashboard as online payments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Subscription and recurring billing$q$, $q$Tools for setting up recurring charges and managing subscription payment flows.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Fraud prevention and risk management$q$, $q$Built-in fraud detection and risk tools to reduce chargebacks and fraudulent transactions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Marketplace payment splitting$q$, $q$Supports splitting payments across multiple vendors for marketplace and platform business models.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$E-commerce platform plugins$q$, $q$Pre-built integrations for Shopify, WooCommerce, Magento, and other popular e-commerce platforms.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Transaction reporting and reconciliation$q$, $q$Detailed dashboards and exportable reports for financial reconciliation and accounting.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Transparent, pay-per-transaction pricing with no monthly fees on the base online plan$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Broad support for local European payment methods that boost conversion, like iDEAL$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$No lock-in contracts and fast onboarding for new merchants$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Covers both online and in-person payments from one platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Backed by strong funding and a large customer base across Europe$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Primarily focused on Europe, with less depth in some non-European markets compared to Stripe or Adyen$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Transaction fees vary meaningfully by payment method and card type, which can complicate cost forecasting$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$In-person Pro plan requires a one-year commitment$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Non-EEA card transactions carry noticeably higher fees$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Some advanced enterprise features require custom/volume pricing negotiations$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$What is Mollie used for?$q$, $q$Mollie is used by businesses to accept online and in-person payments across dozens of European and international payment methods through a single API and dashboard.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$How much does Mollie charge per transaction?$q$, $q$Mollie charges pay-per-transaction fees that vary by method, for example around 0.25 EUR plus 1.8% for EEA consumer card payments and a flat fee for iDEAL, with no monthly account fee on the standard online plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Is Mollie only for European businesses?$q$, $q$Mollie is headquartered in Amsterdam and focuses primarily on European payment methods and merchants, though it also supports international card payments and cross-border transactions.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$When was Mollie founded?$q$, $q$Mollie was founded in Amsterdam in 2004 and is licensed as a payment institution by De Nederlandsche Bank, the Dutch central bank.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Does Mollie support subscription billing?$q$, $q$Yes, Mollie provides tools for recurring and subscription billing in addition to one-off payments.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$How does Mollie compare to Stripe or Adyen?$q$, $q$Mollie, Stripe, and Adyen are all payment service providers; Mollie is particularly strong for European local payment methods like iDEAL and markets itself on transparent per-transaction pricing with no monthly fees, while Stripe and Adyen offer broader global reach and more extensive platform tooling.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$European e-commerce checkout$q$, $q$Online retailers integrate Mollie to accept local and international payment methods with high conversion in European markets.$q$, $q$E-commerce businesses in Europe$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Marketplace and platform payments$q$, $q$Multi-vendor marketplaces use Mollie's payment splitting to route funds to different sellers automatically.$q$, $q$Marketplace and platform operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Retail point-of-sale payments$q$, $q$Physical retailers use Mollie's in-person card terminals alongside their online store for unified reporting.$q$, $q$Retail and hospitality businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Standard (Pay-as-you-go)$q$, $q$No monthly fee; per-transaction fees from around 0.25 EUR + 1.8%$q$, $q$Per transaction$q$, NULL, $q$["No lock-in contract","Dozens of payment methods","Online and in-person payments","Standard reporting and reconciliation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$In-Person Pro$q$, $q$EUR 20/month$q$, $q$Monthly (1-year commitment)$q$, NULL, $q$["Reduced in-person transaction rates","Point-of-sale card readers","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$Volume/Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Discounted rates for over EUR 100,000/month volume","Dedicated account manager","Startup fee waivers up to EUR 1,000,000 in volume (eligibility-based)"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mollie is a European payment service provider that lets businesses accept online and in-person payments through a single API and dashboard, covering dozens of payment methods across the region. Founded in Amsterdam in 2004, Mollie is licensed by De Nederlandsche Bank and now serves more than 200,000 businesses.$q$, $q$The company has raised over $1 billion in funding, including an $800 million Series C in 2024 led by Blackstone Growth at a roughly $6.5 billion valuation, and now employs over 1,000 people across offices throughout Europe.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Mollie's core product is a unified checkout that supports major card networks alongside local European methods like iDEAL, SEPA Direct Debit, SEPA Bank Transfer, Klarna, Apple Pay, and Google Pay, all through a single integration. It offers plugins for common e-commerce platforms like Shopify, WooCommerce, and Magento, along with a developer-friendly API.$q$, $q$Beyond checkout, Mollie supports subscription and recurring billing, fraud prevention, multi-currency settlement, detailed reporting and reconciliation, and payment splitting for marketplaces and platforms with multiple vendors.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d50744af-e272-48a8-a0dc-044078b5dab2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mollie uses transparent, pay-per-transaction pricing with no monthly account fees for standard online payments and no lock-in contracts. Card payments from EEA consumers start around 0.25 EUR plus 1.8%, while iDEAL and SEPA Direct Debit carry their own flat or blended rates.$q$, $q$For in-person payments, Mollie offers a free pay-as-you-go tier alongside a 20 EUR per month Pro plan with lower transaction rates and a one-year commitment. Larger businesses processing over 100,000 EUR monthly can access custom volume pricing, and qualifying startups may get waived fees on early processing volume.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Customizable deal pipelines$q$, $q$Visual, drag-and-drop pipelines that sales teams can fully reconfigure to match their own sales process.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Two-way email sync$q$, $q$Syncs with Gmail and Outlook so emails and CRM records stay updated automatically in both directions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$AI-powered email and enrichment$q$, $q$Generates email drafts and enriches lead and contact data using built-in AI tools.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$No-code automations$q$, $q$Automates repetitive sales tasks like stage changes, notifications, and follow-up reminders without code.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Sales dashboards and forecasting$q$, $q$Visual dashboards that roll up pipeline data into forecasts and performance reporting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Quotes and invoices$q$, $q$Generates quotes and invoices directly from CRM deal records to support the closing process.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Lead capture forms$q$, $q$Customizable web forms that feed new leads directly into the CRM pipeline.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$150+ templates$q$, $q$A large library of pre-built templates for sales, marketing, and related workflows to speed up setup.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Highly visual, flexible interface that is easy for teams to customize and adopt$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Inherits monday.com's powerful no-code automation engine and integrations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Combines pre-sales pipeline management with post-sales account and project tracking$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$AI-assisted email generation and lead enrichment built into paid plans$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Large template library speeds up setup for common sales workflows$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Three-seat minimum can feel expensive for very small sales teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Key CRM features are locked behind higher-priced tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Flexibility means more setup effort compared to opinionated, sales-only CRMs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Reporting and forecasting are less specialized than dedicated sales-analytics CRMs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Pricing structure has changed multiple times, making cost comparisons across years inconsistent$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$What is Monday Sales CRM?$q$, $q$Monday Sales CRM is a purpose-built CRM product from monday.com, built on the same Work OS platform as the company's general project-management tool, but pre-configured for sales pipeline, contact, and post-sale management.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$How much does Monday Sales CRM cost?$q$, $q$Monday Sales CRM starts around $12 per seat per month for the Basic tier billed annually, with Standard around $17, Pro around $28, and custom Enterprise pricing, subject to a three-seat minimum.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Is Monday Sales CRM the same as monday.com?$q$, $q$No. Monday Sales CRM is a specific CRM product built on the broader monday.com Work OS platform, while monday.com itself is a general-purpose work management and project tracking tool.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Does Monday Sales CRM integrate with email?$q$, $q$Yes, it offers two-way email sync with Gmail and Outlook, along with email templates, sequences, and mass email sending.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Is there a free trial for Monday Sales CRM?$q$, $q$Yes, monday.com offers a 14-day free trial on Monday Sales CRM paid plans.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$How does Monday Sales CRM compare to HubSpot or Pipedrive?$q$, $q$Monday Sales CRM offers more visual, no-code customization of pipelines and fields than most dedicated CRMs like Pipedrive, while HubSpot CRM offers a more extensive built-in marketing suite; Monday Sales CRM sits closer to a flexible, board-based CRM than a fully opinionated sales platform.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Sales pipeline management$q$, $q$Sales teams track deals from lead to close using customizable, visual pipeline boards.$q$, $q$Sales representatives and managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Post-sale account management$q$, $q$Account managers use the same CRM to manage onboarding, renewals, and ongoing client projects after a deal closes.$q$, $q$Account and customer success managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Lead capture and outreach$q$, $q$Marketing and sales teams capture leads via forms and run email sequences directly from the CRM.$q$, $q$SMB sales and marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Up to 2 seats","Basic contact and lead tracking","Limited boards"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Basic CRM$q$, $q$About $12/seat/month$q$, $q$Annual$q$, NULL, $q$["Unlimited contacts and deals","Basic pipeline management","Mobile apps"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Standard CRM$q$, $q$About $17/seat/month$q$, $q$Annual$q$, NULL, $q$["Two-way email sync","Sales forecasting","Automations and integrations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Pro CRM$q$, $q$About $28/seat/month$q$, $q$Annual$q$, NULL, $q$["AI email generation and enrichment","Advanced automations","Sales analytics dashboards"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$Enterprise$q$, $q$Custom$q$, $q$Annual/Custom$q$, NULL, $q$["Enterprise-grade security","Advanced permissions","Dedicated support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Monday Sales CRM is a dedicated CRM product built by monday.com Ltd on top of its broader Work OS platform, designed specifically for sales teams managing pipelines, contacts, and post-sale relationships. It differs from general-purpose monday.com boards by shipping pre-configured CRM templates, fields, and AI tools tuned for sales workflows out of the box.$q$, $q$monday.com itself was founded in Tel Aviv in 2012 by Roy Mann and Eran Zinman under the name dapulse, rebranded in 2017, and went public on Nasdaq in 2021. Monday Sales CRM launched as one of several standalone products (alongside Work Management, monday dev, and monday service) built on the same underlying visual, no-code platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Monday Sales CRM includes customizable deal pipelines, contact and account records, and lead capture forms for managing the full sales lifecycle in one place. Two-way email sync with Gmail and Outlook, templated email sequences, and mass email tools support outreach directly from the CRM.$q$, $q$AI features assist with email generation and lead data enrichment, while no-code automations handle repetitive tasks like stage updates and follow-up reminders. Visual dashboards support sales forecasting, and built-in quote and invoice tools extend the CRM into post-sale account and project management.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Monday Sales CRM uses seat-based subscription pricing with a minimum of three seats. Annual billing tiers run from Basic at around $12 per seat per month, Standard at around $17, and Pro at around $28, with Enterprise available on custom quotes.$q$, $q$Choosing annual billing saves roughly 18% compared to paying monthly, and monday.com offers a 14-day free trial on paid CRM plans so sales teams can evaluate pipeline and automation features before committing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('639091c6-3897-46d2-b20e-6a7dfd423bec', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Customizable boards$q$, $q$Flexible grid-based boards with configurable columns that can be visualized as tables, Kanban, timelines, or calendars.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$No-code automations$q$, $q$Rule-based automations that trigger actions like notifications, status changes, and task assignments without coding.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Multi-product Work OS suite$q$, $q$Four standalone products (Work Management, CRM, dev, service) built on one shared platform and account.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Dashboards and reporting$q$, $q$Customizable dashboards that aggregate data across boards for high-level reporting and visibility.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Native integrations$q$, $q$Pre-built integrations with tools like Slack, Gmail, Outlook, Zoom, and Jira to connect existing workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$AI-assisted features$q$, $q$AI tools for summarizing updates, generating content, and assisting with task management.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Time tracking and Gantt views$q$, $q$Built-in time tracking plus Gantt and timeline views for scheduling and resource planning.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Templates library$q$, $q$Over 200 pre-built templates across departments and use cases to accelerate setup.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Highly visual and flexible interface that adapts to many different workflows$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Strong no-code automation and integration ecosystem$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Single platform spans project management, CRM, dev, and service use cases$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Large template library shortens setup time for new teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Public company with strong financial backing and frequent feature investment$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Pricing scales quickly for larger teams, especially on Pro and Enterprise tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Minimum three-seat requirement and 5-seat increments can be awkward for small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Advanced features like time tracking and Gantt views are locked to higher tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Can become complex to administer at scale with many boards and automations$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Some core reporting and automation limits require moving up a paid tier$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$What is monday.com used for?$q$, $q$monday.com is used as a general-purpose Work OS for project management, task tracking, operations, marketing workflows, and cross-team collaboration, using customizable no-code boards and automations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$How much does monday.com cost?$q$, $q$monday.com offers a free plan for up to two seats, with paid plans starting around $9 per seat per month for Basic (billed annually), scaling to Standard, Pro, and custom Enterprise pricing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Who founded monday.com?$q$, $q$monday.com was founded in Tel Aviv in 2012 by Roy Mann and Eran Zinman, originally under the name dapulse, before rebranding to monday.com in 2017.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Is monday.com publicly traded?$q$, $q$Yes, monday.com Ltd went public on Nasdaq on June 10, 2021, after filing for its IPO in May 2021.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$What is the difference between monday.com and Monday Sales CRM?$q$, $q$monday.com is the general-purpose Work OS platform for project and work management, while Monday Sales CRM is a specific, pre-configured product built on the same platform and priced separately, focused on sales pipeline management.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$How does monday.com compare to Asana or ClickUp?$q$, $q$monday.com, Asana, and ClickUp are all work management platforms; monday.com is known for its highly visual, spreadsheet-like board customization and its multi-product Work OS suite spanning CRM, dev, and service use cases beyond core project management.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Cross-team project management$q$, $q$Teams plan, track, and report on projects using customizable boards, timelines, and dashboards.$q$, $q$Project managers and operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Marketing campaign planning$q$, $q$Marketing teams use monday.com boards to plan content calendars, campaigns, and creative workflows.$q$, $q$Marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Enterprise workflow standardization$q$, $q$Large organizations standardize processes across departments using monday.com's Work OS and its Work Management, CRM, dev, and service products together.$q$, $q$Enterprise operations and IT leaders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Up to 2 seats","Up to 3 boards","200+ templates","Mobile apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Basic$q$, $q$About $9/seat/month$q$, $q$Annual$q$, NULL, $q$["Unlimited items","Unlimited free viewers","Basic AI tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Standard$q$, $q$About $12/seat/month$q$, $q$Annual$q$, NULL, $q$["Timeline and Gantt views","Calendar view","Guest access","250 automations/month"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Pro$q$, $q$About $19/seat/month$q$, $q$Annual$q$, NULL, $q$["Private boards and docs","Time tracking","25,000 automations/month","Advanced columns"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$Enterprise$q$, $q$Custom$q$, $q$Annual/Custom$q$, NULL, $q$["Enterprise-grade security and governance","Portfolio and resource management","Multi-level permissions","99.9% uptime SLA"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$monday.com is a cloud-based Work Operating System that lets teams build fully customizable boards, dashboards, and automated workflows without writing code, spanning project management, operations, marketing, and cross-team collaboration. Its flexible board-and-column architecture can be reshaped into tables, Kanban boards, Gantt timelines, or calendars depending on the team's needs.$q$, $q$The company was founded in Tel Aviv in 2012 by Roy Mann and Eran Zinman as dapulse Labs, rebranded to monday.com in 2017, and went public on Nasdaq in June 2021 after raising roughly $235 million in prior funding. It now employs well over 2,000 people across offices in Tel Aviv, New York, London, and other cities.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$monday.com's platform is organized around four standalone products built on a shared Work OS foundation: monday Work Management for general project tracking, monday CRM for sales, monday dev for software teams, and monday service for IT/customer service. All four share the same automation engine, integrations, and dashboard tools.$q$, $q$Core capabilities include no-code automations, over 200 pre-built templates, native integrations with tools like Slack, Gmail, and Jira, AI features for summarizing updates and generating content, time tracking, Gantt/timeline views, and granular permissions including private boards and guest access.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$monday.com uses a freemium, seat-based subscription model with five tiers: Free (up to two seats), Basic (around $9 per seat per month annually), Standard (around $12), Pro (around $19), and custom-priced Enterprise. Seats are sold in blocks, starting at a minimum of three and scaling in increments of five.$q$, $q$Annual billing offers a meaningfully lower per-seat rate than monthly billing, and higher tiers unlock more automation and API call allowances, advanced views like Gantt and timeline, and enterprise-grade security and governance controls.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7bc1e8a6-de99-4eb8-9968-c92bb4254013', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
