-- в”Ђв”Ђ MODX в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$MODX is an open-source PHP content management system and framework that gives developers full control over markup to build custom, semantic websites without a fixed theme structure.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid MODX Cloud hosting from about $39/month)$q$, starting_price),
  founded_year = COALESCE(2004, founded_year),
  company_size = COALESCE($q$Small (privately held, under 50 employees)$q$, company_size),
  headquarters = COALESCE($q$Dallas, Texas, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$MODX Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$MODX CMS review 2026: an open-source, developer-first PHP content management framework. Features, MODX Cloud pricing, and top CMS alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$MODX is an open-source content management system and framework built on PHP, created in 2004 by developers Raymond Irving and Ryan Thrash, with Jason Coward joining the project leadership team in 2005. The founders wanted a CMS that let them build websites with fully semantic HTML, styled purely with CSS, and no existing platform met that bar, so they built and open-sourced what became MODX Evolution. MODX LLC was formally established in May 2010, and later that year the team released MODX Revolution, a complete architectural rewrite of the original CMS that remains the actively developed branch today. The company is privately held and based in Dallas, Texas, with its original founders still guiding the project. In October 2012, MODX launched MODX Cloud, a managed hosting service built specifically for MODX sites. Architecturally, MODX distinguishes itself from theme-driven CMS platforms like WordPress by imposing no default templates or markup: every element of the front end is built from scratch using MODX's own tag-based templating (Chunks, Snippets, Templates, and Template Variables), giving developers precise control over HTML output, which the project calls its 'anti-bloat' or 'Creative Freedom' philosophy. It uses a resource-based content model rather than a rigid post/page hierarchy, making it flexible for both traditional websites and more complex content structures. Core features include a manager (admin) back end for content editing, a plugin and extra ecosystem for extending functionality, granular user and permission management, multi-language support, and strong SEO-friendly URL handling out of the box. Because MODX is open source, the core software is free to download and self-host on any PHP-compatible server; premium add-ons from community developers have existed since 2013. For teams that do not want to self-host, MODX offers managed MODX Cloud hosting with tiered pricing: a Base plan around $39 per month, a Pro plan around $99 per month, and a Business plan around $349 per month, with custom Enterprise plans starting around $4,000 per month on a 3-year commitment; optional add-ons include staging environments, CDN/WAF protection, and multi-datacenter failover. MODX's target audience is developers, agencies, and technically sophisticated teams building custom-designed marketing sites, brochure sites, and small-to-midsize business websites who want full control over markup rather than a page-builder experience. Its main competitors include WordPress, Craft CMS, ProcessWire, and other open-source PHP CMS platforms, as well as headless CMS options. MODX differentiates itself through its markup-agnostic templating, long operating history since 2004, and a managed cloud hosting arm that generates revenue alongside the free open-source core.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ba2afed9-4dd0-452e-8365-2334d0c54742';

